<!doctype html><html><head><meta charset="utf-8"><script src="https://cdn.tailwindcss.com"></script><title>Company Settings</title></head><body class="bg-slate-50"><main class="mx-auto max-w-2xl p-8"><h1 class="text-3xl font-bold">Company settings</h1>@if(session('status'))<p class="mt-4 rounded bg-green-100 p-3 text-green-800">{{ session('status') }}</p>@endif<form class="mt-8 space-y-4 rounded bg-white p-6 shadow" method="POST" enctype="multipart/form-data" action="/settings/company">@csrf<input class="w-full rounded border p-3" name="company_name" value="{{ old('company_name', $workspace->settings?->company_name ?? $workspace->name) }}"><input class="w-full rounded border p-3" name="timezone" value="{{ old('timezone', $workspace->settings?->timezone ?? 'Asia/Dhaka') }}"><input class="w-full rounded border p-3" name="currency" value="{{ old('currency', $workspace->settings?->currency ?? 'BDT') }}"><input class="w-full rounded border p-3" type="file" name="logo"><div class="rounded border p-4"><h2 class="font-semibold">AI settings</h2><p class="text-sm text-amber-700">AI output is suggestion only. Managers/owners must approve important actions.</p><label class="mt-3 flex items-center gap-2"><input type="checkbox" name="ai_enabled" value="1" @checked(old('ai_enabled', $workspace->settings?->ai_enabled))> Enable AI</label><select class="mt-3 w-full rounded border p-3" name="ai_preferred_provider">@php($provider=old('ai_preferred_provider', $workspace->settings?->feature_flags['ai_preferred_provider'] ?? config('ai.default_provider')))<option value="disabled" @selected($provider==='disabled')>Disabled</option><option value="local" @selected($provider==='local')>Local</option><option value="cloud" @selected($provider==='cloud')>Cloud</option><option value="hybrid" @selected($provider==='hybrid')>Hybrid</option></select></div><button class="rounded bg-slate-900 px-5 py-3 text-white">Update settings</button></form></main></body></html>
